INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Write a single honest sentence about the moment or feeling. No need for structure — just capture the essence."},"content":{"tips":"Write freely. This is for you. Be honest, be specific, use sensory details. Short entries are perfectly fine."},"formatting":["Paragraphs: the default format for reflective writing","Bullet lists: gratitude items, things noticed, intentions","Bold: emphasize a key realization or feeling","Blockquotes: something someone said that stayed with you"],"avoid":["Writing for an audience when the entry is private","Judging your own feelings — just observe them","Vague entries like \"Today was fine\" without detail","Over-structuring what should be freeform reflection"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":5,"max":100},"content":{"min":1,"max":5000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

